import React, { useState, useEffect, useRef } from 'react';
import { Document, Page, pdfjs } from 'react-pdf';
import 'react-pdf/dist/Page/AnnotationLayer.css';
import 'react-pdf/dist/Page/TextLayer.css';

// 🔑 CONFIGURATION CORRECTE POUR CRA
const PDFJS_VERSION = '5.4.296';
pdfjs.GlobalWorkerOptions.workerSrc = `https://cdn.jsdelivr.net/npm/pdfjs-dist@${PDFJS_VERSION}/legacy/build/pdf.worker.min.js`;

interface PDFViewerProps {
  fileUrl: string;
  onDocumentLoad?: (numPages: number) => void;
}

const PDFViewer: React.FC<PDFViewerProps> = ({ fileUrl, onDocumentLoad }) => {
  const [numPages, setNumPages] = useState<number | null>(null);
  const [pageNumber, setPageNumber] = useState(1);
  const [scale, setScale] = useState(1.0);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const isMounted = useRef(true);

  useEffect(() => {
    return () => { isMounted.current = false; };
  }, []);

  useEffect(() => {
    setLoading(true);
    setError(null);
    setPageNumber(1);
  }, [fileUrl]);

  const onDocumentSuccess = (pdf: any) => {
    if (!isMounted.current) return;
    setNumPages(pdf.numPages);
    setLoading(false);
    if (onDocumentLoad) onDocumentLoad(pdf.numPages);
  };

  const onDocumentError = (err: any) => {
    if (!isMounted.current) return;
    console.error('❌ Erreur PDF:', err);
    
    let message = '📄 Impossible de charger le PDF';
    if (err.status === 403) {
      message = '🔐 Bucket Supabase non public\nAllez dans Storage → document-files → Settings → Activez "Public"';
    }
    
    setError(message);
    setLoading(false);
  };

  const goToPrevPage = () => setPageNumber(prev => Math.max(prev - 1, 1));
  const goToNextPage = () => setPageNumber(prev => Math.min(prev + 1, numPages || 1));

  return (
    <div className="h-full flex flex-col">
      {/* Barre d'outils */}
      <div className="flex items-center justify-between p-3 border-b border-gray-200 dark:border-gray-700 bg-white dark:bg-gray-700/50">
        <div className="flex items-center gap-3">
          <button onClick={goToPrevPage} disabled={pageNumber <= 1 || loading} className="p-1.5 rounded-md text-gray-700 dark:text-gray-300">
            <i className="fas fa-chevron-left"></i>
          </button>
          <span className="text-sm">Page {pageNumber} / {numPages || '?'}</span>
          <button onClick={goToNextPage} disabled={pageNumber >= (numPages || 1) || loading} className="p-1.5 rounded-md text-gray-700 dark:text-gray-300">
            <i className="fas fa-chevron-right"></i>
          </button>
        </div>
      </div>
      
      {/* Zone de visualisation */}
      <div className="flex-1 overflow-auto bg-white dark:bg-gray-800 flex items-center justify-center p-4 relative">
        {loading && (
          <div className="absolute inset-0 flex items-center justify-center bg-white/90 dark:bg-gray-800/90 z-10">
            <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-blue-600 mb-3"></div>
            <p className="text-gray-600 dark:text-gray-400">Chargement...</p>
          </div>
        )}
        
        {error && (
          <div className="absolute inset-0 flex items-center justify-center z-10 text-red-600 dark:text-red-400 p-4 text-center">
            <div>{error}</div>
          </div>
        )}
        
        <Document
          file={fileUrl}
          onLoadSuccess={onDocumentSuccess}
          onLoadError={onDocumentError}
          className="max-w-full"
        >
          <Page
            pageNumber={pageNumber}
            scale={scale}
            renderTextLayer={true}
            renderAnnotationLayer={true}
            className="shadow-lg rounded-lg"
          />
        </Document>
      </div>
    </div>
  );
};

export default PDFViewer;
